-- ============================================================

-- 1. Roofers × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'roofers',
  'web-design',
  'When a homeowner discovers water dripping through their ceiling during a storm, they grab their phone and search for emergency roofer near me. In that moment, your website must instantly communicate that you handle emergencies, that you are available, and that you are trustworthy enough to let onto their roof. But roofing is not only about emergencies. A homeowner planning a full roof replacement worth ten to twenty thousand pounds will research extensively before committing, comparing portfolios, checking credentials, and reading reviews across multiple roofing companies. Your website must serve both audiences simultaneously: the panicked homeowner with water coming through the ceiling and the careful planner investing in a major home improvement. Most roofing websites fail both groups. Emergency callers cannot find a phone number quickly. Planned project customers see a generic services page with no project gallery, no material comparisons, and no indication of whether you handle their specific roof type. We build roofing websites that provide instant emergency contact above the fold on mobile, comprehensive service pages for every roofing discipline from slate repairs to flat roof installations, detailed project galleries showing completed work on similar properties, and clear information about the materials and systems you recommend. The result is a website that converts emergency callers into immediate jobs and careful planners into high-value projects.',
  'Roofing work carries a unique trust requirement because homeowners cannot easily verify what has been done once the scaffolding comes down. They are trusting your expertise, your materials, and your workmanship for the next twenty to forty years. A professional website that displays your credentials, showcases completed projects with before-and-after photography, and provides detailed information about materials and guarantees addresses the trust deficit that prevents homeowners from committing to what is often the largest maintenance spend on their property.',
  'We design roofing websites around the two distinct customer journeys: emergency leak repair with instant contact, and planned roofing projects with comprehensive service information. Emergency banners are visible on mobile without scrolling. Project galleries are organised by roof type: slate, tile, flat roof, lead work, and chimney repairs. Material comparison pages help customers understand their options.',
  '[{"title": "Emergency callers unable to reach you during storm events", "description": "Storm damage and roof leaks generate the most urgent roofing searches. When a homeowner with water pouring through their ceiling finds your website and cannot immediately see a phone number and confirmation that you handle emergencies, they press back and call the next roofer. These emergency calls are your highest-margin, most time-sensitive leads."}, {"title": "No project gallery showing completed roofing work by type", "description": "A homeowner planning a full slate roof replacement wants to see that you have completed similar work on similar properties. A generic gallery mixing small repairs with major projects does not provide this reassurance. Without categorised project showcases organised by roof type and material, planned project customers cannot assess your capability for their specific requirements."}, {"title": "No material information helping customers understand their roofing options", "description": "Homeowners investing in a new roof want to understand the difference between natural slate and synthetic alternatives, between clay tiles and concrete, between single-ply flat roofing and traditional felt systems. When your website provides no material guidance, customers feel uninformed and delay their decision, often choosing the competitor who helped them understand their options."}]',
  '[{"title": "Emergency-first mobile design with storm response messaging", "description": "A persistent emergency banner with click-to-call functionality on every page, visible without scrolling on mobile. Storm event messaging confirms you handle emergency leak repairs with same-day response. After-hours availability information ensures callers at midnight during a storm know they can reach you. This captures the most urgent and valuable leads in roofing."}, {"title": "Categorised project gallery organised by roof type and material", "description": "Completed project galleries organised by discipline: slate roofing, tile replacement, flat roof installations, lead work, chimney repairs and rebuilds, and fascia and soffit replacement. Each project includes before-and-after photography, a description of the work completed, materials used, and the approximate scope. Customers find evidence of your competence for their exact project type."}, {"title": "Material comparison and roofing system information pages", "description": "Detailed pages comparing natural slate versus synthetic, clay versus concrete tiles, and modern flat roofing systems versus traditional approaches. Each page explains the advantages, lifespan, cost implications, and aesthetic considerations. This educational content serves customers in the research phase and positions your company as knowledgeable advisors rather than just contractors."}]',
  '[{"question": "How do you make a roofing website generate emergency leak repair work?", "answer": "Emergency design is about instant visibility and trust. A click-to-call phone number in a high-contrast banner appears on every page without scrolling. Messaging confirms you handle emergency roof repairs with rapid response. Schema markup tells Google your business provides emergency roofing services, improving visibility for urgent searches during storm events."}, {"question": "Should we show our completed roofing projects on the website?", "answer": "Absolutely. Before-and-after project photography is the most powerful trust-building content for roofers. We organise your projects by roof type so customers planning a slate roof replacement find slate examples, and those needing flat roof work find flat roof completions. Each project tells a visual story from problem to solution."}, {"question": "How important are material comparison pages for a roofing website?", "answer": "Very. Homeowners investing in a new roof want to understand their options before committing. Material comparison content builds trust by demonstrating your knowledge and helping customers make informed decisions. These pages also rank well for research-phase search terms like best roofing tiles or slate versus synthetic roof, capturing customers early in their journey."}, {"question": "Can the website handle both emergency repairs and large project enquiries?", "answer": "Yes. We build separate pathways for each. Emergency visitors see instant contact options and rapid response messaging. Planned project visitors navigate to detailed service pages, view relevant project galleries, and submit comprehensive enquiry forms that capture roof type, property details, and project scope. Each audience gets the experience their urgency demands."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Roofers × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'roofers',
  'seo',
  'Roofing searches split into two categories that together represent one of the most valuable local SEO opportunities in the trades. Emergency searches like roof leak repair, emergency roofer near me, and storm damage roof repair spike dramatically during bad weather and convert almost instantly because the homeowner needs help immediately. Planned project searches like roof replacement cost, slate roofer Kent, and flat roof installation near me represent considered purchases worth thousands or tens of thousands of pounds. Most roofing companies have no deliberate SEO strategy, relying on a single homepage and perhaps a generic services page that fails to rank for any specific roofing search term. The companies dominating roofing search results have dedicated, optimised pages for every service they offer, every material they work with, and every geographic area they serve. Our SEO campaigns for roofers exploit the full range of roofing search terms by building targeted content for each service category, each roof type, each material system, and each location within your service area. We also implement weather-responsive strategies that capitalise on the dramatic search spikes that follow storms, heavy rain, and severe weather events across Kent.',
  'Roofing is one of the most searched-for trades online because roof problems are both urgent and expensive. Emergency leak repairs generate immediate phone calls, while planned roof replacements represent the highest-value projects in domestic construction. Ranking for these searches puts your business in front of customers at the moment they are ready to spend. Every position lost in search results represents thousands of pounds in annual revenue redirected to competitors who invested in their visibility.',
  'We build roofing SEO around service categories, material types, and weather-driven search patterns. Individual pages target slate roofing, tile replacement, flat roofing, lead work, and chimney repairs. Material-specific content captures research-phase searches. Storm damage and emergency content is pre-built and ready to promote when severe weather hits your area.',
  '[{"title": "Invisible for emergency roofer searches during storm events", "description": "Search volume for emergency roofer spikes by hundreds of percent during severe weather. The roofing companies visible in Google during these events capture weeks of work in a single day. Without emergency-optimised pages and a Google Business Profile declaring emergency availability, your business is invisible during the most lucrative searching conditions in the roofing trade."}, {"title": "No rankings for high-value roof replacement and installation searches", "description": "Searches for roof replacement cost, new slate roof price, and flat roof installation near me represent homeowners planning projects worth five to twenty thousand pounds. These searches are competitive but achievable with dedicated, well-optimised service pages. Without individual pages targeting these specific terms, your website cannot rank against competitors who have them."}, {"title": "Generic services page competing against specialists with detailed content", "description": "A single page listing roof repairs, replacements, flat roofing, leadwork, and chimney repairs cannot rank for any individual service against competitors who dedicate entire pages to each discipline. Google rewards depth and specificity. Your breadth of services should create SEO advantages, but without dedicated pages for each service, it creates ranking disadvantages."}]',
  '[{"title": "Service-specific landing pages for every roofing discipline", "description": "Individual optimised pages for roof repairs, full replacements, slate roofing, tile work, flat roof installation and repair, lead work, chimney repairs and rebuilds, fascia and soffit replacement, and roof cleaning. Each page targets the specific search terms customers use for that service, creating multiple ranking opportunities from a single website."}, {"title": "Emergency roofing SEO with weather-responsive activation", "description": "Dedicated emergency pages targeting storm damage, roof leak, and emergency roofer searches with structured data declaring emergency availability and rapid response. Pre-built content optimised for severe weather events can be activated quickly when storms hit, capitalising on the dramatic search spikes that follow bad weather across Kent."}, {"title": "Material and roof-type authority content for research-phase searches", "description": "In-depth content covering every roofing material: natural slate varieties, clay and concrete tiles, single-ply flat roofing membranes, lead sheet work, and GRP fibreglass systems. This technical content attracts customers researching their options, builds topical authority that improves rankings across all your pages, and positions your company as material experts."}]',
  '[{"question": "How quickly can we rank for emergency roofer searches?", "answer": "Google Business Profile optimisation can improve Map Pack visibility within four to six weeks. Emergency-specific landing pages typically begin ranking within two to four months. We prioritise emergency visibility because storm-driven traffic converts at the highest rate in the roofing trade and represents your most time-sensitive ranking opportunity."}, {"question": "Should we create separate pages for slate, tile, and flat roofing?", "answer": "Absolutely. Each material and roof type has its own set of search terms with distinct search volume. A homeowner searching for slate roofer near me has different needs and expectations than one searching for flat roof replacement. Dedicated pages for each type target these distinct audiences and rank for their specific search terms."}, {"question": "How do we capitalise on storm damage search spikes?", "answer": "We pre-build storm damage and emergency content optimised for the search terms that spike during severe weather. Your Google Business Profile is maintained with emergency availability status. When storms hit your area, these assets capture the surge in search demand. Combined with your ongoing emergency SEO, this ensures visibility exactly when homeowners need you most."}, {"question": "Is it worth targeting searches about roofing materials and costs?", "answer": "Yes. These research-phase searches attract homeowners who will spend thousands on roofing work within months. Content about slate versus synthetic, roof replacement costs, and material comparisons captures these prospects early in their decision journey. When they are ready to request quotes, your company is already established as the knowledgeable local choice."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 3. Roofers × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'roofers',
  'lead-capture',
  'Roofing leads arrive with wildly different urgency levels and dramatically different values. An emergency leak repair call during a storm needs immediate phone contact and generates a callout fee plus repair work. A homeowner requesting a quote for a full roof replacement represents a project worth ten to twenty thousand pounds but requires a thorough site survey and detailed quotation. A landlord enquiring about roof maintenance across multiple properties represents recurring annual revenue. Most roofing websites offer a single phone number and a generic contact form that handles all three scenarios identically, which means they handle none of them well. Emergency callers cannot tell if you offer rapid response. Planned project customers submit vague messages with no details about their roof type or property. Landlords are treated the same as someone with a loose ridge tile. Our lead capture systems for roofers create distinct pathways for each enquiry type. Emergency callers get instant click-to-call with storm response messaging. Planned project customers complete structured forms capturing roof type, property details, problem description, and photos of the issue. Free roof survey landing pages convert research-phase visitors into booked assessments. Storm damage response pages activate during severe weather to capture the surge of urgent enquiries that follows every major storm event.',
  'Roofing leads have the widest value range of any trade: from a fifty-pound ridge tile repair to a twenty-thousand-pound full replacement. Treating every enquiry identically means your highest-value leads receive the same slow, manual response as your smallest jobs. Effective lead capture identifies high-value opportunities instantly, provides appropriate urgency for emergency work, and qualifies planned projects with the detail needed for accurate quoting.',
  'We build roofing lead capture around urgency triage and project value. Emergency visitors see click-to-call with same-day response messaging. Free roof survey landing pages convert planners into booked assessments. Storm damage response pages activate when bad weather creates surges. Structured project forms capture roof type, property age, and photos for accurate quoting.',
  '[{"title": "Emergency leak callers unable to confirm you offer rapid response", "description": "During a storm, a homeowner with water coming through their ceiling needs to know immediately that you handle emergencies and that you can come today. If your website provides no emergency-specific messaging and no confirmation of rapid response capability, the caller assumes you are a planned-work-only roofer and calls someone else. The emergency lead is gone in seconds."}, {"title": "Free roof survey offers not converting research-phase visitors", "description": "Many homeowners suspect they need roofing work but are not sure about the scope or cost. A free roof survey is the most effective conversion offer for these visitors, but most roofing websites either do not offer surveys or bury the offer in generic service page text. Without a dedicated, prominent survey landing page, these warm leads leave without taking action."}, {"title": "Storm damage enquiries overwhelming your capacity with no triage system", "description": "After a major storm, you might receive thirty to fifty enquiries in a single day. Without a system that captures detailed information, categorises severity, and prioritises responses, your team is overwhelmed by phone calls and vague messages. Genuine emergencies with water ingress get the same delayed response as cosmetic damage from a dislodged ridge tile."}]',
  '[{"title": "Emergency leak capture with storm response activation", "description": "A persistent emergency banner with click-to-call and same-day response messaging on every page. During severe weather events, storm damage response pages activate with specific messaging about temporary repairs, insurance claim support, and priority scheduling. These pages capture the enquiry surge following storms and triage genuine emergencies for immediate dispatch."}, {"title": "Free roof survey landing pages for planned project conversion", "description": "Dedicated landing pages offering free roof surveys and assessments. Visitors enter their property details, roof type, and concern description. The form captures photos of visible issues. Survey requests are qualified by property type and potential project value, ensuring your surveyor''s time is allocated to the opportunities with the highest potential return."}, {"title": "Structured project enquiry forms with photo upload and roof-type selection", "description": "Multi-step forms that capture roof material type, property age, the nature of the problem, accessibility, and photographic evidence of the issue. This information allows you to provide informed responses and prioritise survey visits. High-value indicators like full replacement interest and property portfolio ownership are flagged automatically for priority follow-up."}]',
  '[{"question": "How does the storm damage response system work?", "answer": "Pre-built storm response pages sit dormant on your website until severe weather is forecast or underway. When activated, they become the primary landing point for storm damage searches, capturing property details, damage descriptions, photos, and urgency levels. Submissions are triaged automatically: active water ingress is flagged for immediate response while cosmetic damage is scheduled for assessment."}, {"question": "Can the free roof survey form qualify the size of the potential project?", "answer": "Yes. The form captures property type, approximate roof size, roof material, age of the current roof, and the nature of the concern. Combined with uploaded photos, this information helps you assess whether the enquiry is a minor repair or a potential full replacement before committing survey time. High-value indicators trigger priority scheduling."}, {"question": "How do you handle the surge of enquiries after a storm?", "answer": "The storm response system captures detailed information from every enquiry including damage severity and water ingress status. Automated acknowledgement emails confirm receipt and provide temporary repair guidance. Your team reviews a triaged queue rather than fielding dozens of phone calls, allowing you to dispatch to genuine emergencies first and schedule assessments for less urgent damage systematically."}, {"question": "Can the system capture photos of roof damage from the homeowner?", "answer": "Yes. The enquiry forms include photo upload functionality where homeowners can submit images of visible damage, internal water staining, or concerns they have noticed. These photos give your team a preliminary assessment of the issue before visiting, reducing wasted journeys and enabling more accurate initial guidance to the customer."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
