-- 4. Roofers × Business Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'roofers',
  'business-automation',
  'Roofing businesses face an administrative challenge that intensifies with weather. When storms hit, enquiries flood in simultaneously, each needing acknowledgement, triage, and scheduling. During fair weather, planned projects require detailed quotations, material ordering, scaffolding coordination, and customer communication across multi-day installations. The seasonal and weather-driven nature of roofing work creates unpredictable workload spikes that manual processes simply cannot handle. Business automation for roofers systematises every repeatable process in your operation. Emergency enquiries receive instant automated acknowledgement with temporary repair guidance while your team assesses severity. Quote follow-up sequences keep proposals active when customers are comparing multiple roofing companies. Material ordering workflows trigger purchase orders when jobs are confirmed. Scaffolding booking requests are generated automatically based on job scheduling. Customer communication sequences provide updates before, during, and after roofing work. Insurance documentation for storm damage claims is generated from job records. Every process that currently depends on someone remembering, checking, or manually initiating is automated so you can handle twice the workload without hiring additional office staff.',
  'Roofing work is weather-dependent and seasonal, creating extreme workload variation that manual administration cannot absorb. After a storm, enquiry volumes can increase tenfold in a single day. During the summer, you might have ten simultaneous multi-day projects requiring coordination. Automation provides the administrative capacity to handle peak demand without the permanent overhead of staff hired for the busiest days of the year.',
  'We automate around the weather-driven and seasonal nature of roofing work. Storm response workflows handle enquiry surges automatically. Quote follow-up sequences recover proposals lost to slow manual follow-up. Scaffolding and material ordering triggers on job confirmation. Insurance claim documentation is generated from job completion records.',
  '[{"title": "Storm enquiry surges overwhelming your administrative capacity", "description": "After a severe storm, you might receive thirty enquiries in a single day when your normal volume is three. Your phone rings constantly, emails pile up, and by the time you work through the queue, half the callers have already booked a competitor. Without automated acknowledgement, triage, and scheduling, storm events create chaos rather than opportunity."}, {"title": "Quote follow-ups not happening because you are on the roof", "description": "You spend the morning on a survey, prepare a detailed quote in the evening, and send it to the customer. Then you are back on the roof for the next three days. The follow-up never happens. The customer, who was comparing three roofers, books with whichever one followed up. Your survey time is wasted and the job goes to a less qualified competitor."}, {"title": "Scaffolding and material coordination adding hours to every project", "description": "Every roofing project requires scaffolding booking, material ordering, and timeline coordination between these suppliers and your installation schedule. A scaffolding delivery that arrives a day late delays the entire project. Materials ordered late push back the start date. Manual coordination of these dependencies creates delays, errors, and frustrated customers."}]',
  '[{"title": "Automated storm response with enquiry triage and acknowledgement", "description": "Every storm enquiry receives instant acknowledgement with temporary repair guidance relevant to their reported damage type. Submissions are automatically triaged by severity: active water ingress is flagged for immediate dispatch, structural damage is scheduled for urgent survey, and cosmetic damage is queued for standard assessment. Your team works a prioritised queue rather than a chaotic inbox."}, {"title": "Quote follow-up sequences calibrated to roofing decision timelines", "description": "Every quote enters an automated follow-up sequence. A check-in two days after sending addresses any questions. A follow-up a week later offers to arrange a second survey if needed. As the customer''s preferred start date approaches, reminders highlight your availability. These sequences recover the quotes that would otherwise be lost to manual follow-up failures."}, {"title": "Scaffolding and material ordering workflows triggered by job confirmation", "description": "When a job is confirmed and scheduled, the system automatically generates scaffolding booking requests with the required dates, access details, and specifications. Material order lists are created from the job specification and sent to your preferred suppliers. Delivery dates are tracked against the project schedule, flagging conflicts before they cause delays."}]',
  '[{"question": "How does the storm response automation handle a sudden surge of enquiries?", "answer": "Every enquiry receives an immediate automated acknowledgement email with relevant temporary repair advice. Submissions are automatically categorised by severity based on the information provided. Your team reviews a triaged, prioritised list rather than an overwhelming inbox. This ensures genuine emergencies are addressed first and no enquiry goes unacknowledged."}, {"question": "Can the system integrate with scaffolding companies for automatic booking?", "answer": "We generate scaffolding booking requests with all necessary specifications, dates, and access information. These can be sent automatically to your preferred scaffolding supplier as structured requests. Where suppliers accept electronic booking, the process is fully automated. Otherwise, pre-populated request forms are generated for your team to send with a single click."}, {"question": "How do the quote follow-up sequences work?", "answer": "After a quote is sent, the system schedules a sequence of follow-ups calibrated to the customer''s project timeline. An initial check-in confirms receipt and invites questions. Subsequent messages address common concerns, share relevant project examples, and remind the customer of your availability. The sequence adjusts automatically if the customer responds at any stage."}, {"question": "Can automation generate insurance claim documentation for storm damage work?", "answer": "Yes. When storm damage work is completed, the system generates documentation suitable for insurance claims: dated photographs, work descriptions, material specifications, and itemised invoicing. This documentation package can be provided to the homeowner or submitted directly to their insurer, adding value to your service and reducing the administrative burden on your customer."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
