  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 5. Roofers × Branding
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'roofers',
  'branding',
  'Roofing is one of the highest-value trades in the domestic market, with individual projects regularly exceeding ten thousand pounds. Yet many roofing companies present themselves with branding that would not look out of place on a handyman''s business card. The disconnect between the scale of investment a customer is making and the visual professionalism of the company they are paying creates a trust gap that costs you quotes. Your brand needs to communicate the expertise, permanence, and reliability that justifies premium pricing for a roof that will protect a family''s home for decades. Your vehicles are your most visible asset, often parked in residential streets with scaffolding and your company name in full view of every neighbour. This is advertising to an audience that has roofs themselves, and your professional appearance during a project directly influences whether neighbours call you when they need roofing work. Beyond your van livery, your brand appears on scaffolding banners, quotation documents, guarantee certificates, and the digital platforms where customers evaluate you. A cohesive brand identity across all these touchpoints builds the perception of an established, professional roofing contractor that customers trust with one of the most significant investments in their property.',
  'Homeowners spending ten to twenty thousand pounds on a roof replacement expect to deal with a professional, established business. Brand presentation that looks amateurish or inconsistent creates doubt about whether your workmanship will match the investment. Professional branding with consistent van livery, scaffolding banners, and documentation signals the organisational maturity and attention to detail that customers need to see before committing to a major roofing project.',
  'We design roofing brands that communicate craftsmanship and permanence. Colour palettes and typography reflect the solidity customers expect from their roof. Van livery maximises neighbourhood visibility during multi-day projects. Scaffolding banners turn every active job site into a local advertisement. Guarantee certificates reinforce long-term quality commitment.',
  '[{"title": "Van livery not reflecting the value of the work you deliver", "description": "When your van is parked outside a property during a fifteen-thousand-pound roof replacement and the livery looks cheap or dated, there is a disconnect between the value of the work and the appearance of the company. Neighbours assessing whether to call you form their impression from your van. Budget-looking branding attracts budget-expectation customers."}, {"title": "No scaffolding banners or site presence during multi-day projects", "description": "A roofing project typically involves scaffolding erected for days or weeks on a residential street. This scaffolding is seen by every person who walks or drives past. Without branded scaffolding banners, this extended exposure generates zero marketing value. A simple banner with your name, phone number, and the work you are doing converts passive observation into active enquiries."}, {"title": "Quotation and guarantee documents lacking professional presentation", "description": "A roof replacement quote presented as a plain email or basic document does not match the gravity of a ten-thousand-pound decision. When customers compare quotes, the one presented in a professional folder with material specifications, guarantee terms, and project visuals communicates higher value. Generic documentation makes a premium service look like a commodity."}]',
  '[{"title": "Premium van livery designed for residential street visibility", "description": "Bold, distinctive livery with a colour scheme that communicates quality and permanence. Your company name, phone number, and website visible from multiple angles. Design elements that reflect roofing craftsmanship without cliche imagery. The livery ensures your presence on every project site generates enquiries from neighbours who see your team delivering quality work."}, {"title": "Scaffolding banners and active project site branding", "description": "Weather-resistant scaffolding banners displaying your company name, phone number, website, and a message about the work underway. Available in multiple sizes for different scaffolding configurations. These banners transform every active project into a local advertising display visible for the entire duration of the work, generating enquiries from the immediate neighbourhood."}, {"title": "Professional quotation and guarantee certificate design", "description": "Quote templates presenting your pricing alongside material specifications, project timelines, warranty terms, and before-and-after examples of similar completed projects. Guarantee certificates for completed work featuring your branding, the materials and systems installed, and the warranty terms. Every document reinforces the professionalism and permanence that justifies your pricing."}]',
  '[{"question": "How effective are scaffolding banners for generating roofing leads?", "answer": "Scaffolding banners are one of the most cost-effective marketing tools available to roofers. A banner displayed for two weeks on a residential street is seen by hundreds of local homeowners, all of whom have roofs themselves. The cost per impression is negligible, and the enquiries generated are highly local, which is exactly your target market."}, {"question": "What colours and style work best for a roofing company brand?", "answer": "Colours that communicate solidity, trust, and craftsmanship perform best: deep blues, slate greys, forest greens, and charcoal paired with clean white or subtle accent colours. The brand should feel established and permanent rather than trendy. Roofing is a long-term investment and your brand should reflect that longevity and quality."}, {"question": "Should our quotes be presented in a branded folder?", "answer": "For projects over a certain value, yes. A roof replacement quote in a branded presentation folder with material samples, warranty information, and project photography communicates that your business treats the customer''s investment seriously. This presentation differentiates you from competitors whose quotes arrive as a figure in a text message or plain email."}, {"question": "Can you design branding that works for both residential and commercial roofing?", "answer": "Absolutely. We design brands that convey professional capability and craftsmanship without being limited to either market. The same identity that impresses a homeowner evaluating roof replacement options should also satisfy a commercial property manager reviewing contractor credentials. The key is communicating quality, reliability, and expertise that translates across both contexts."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
