-- 6. Roofers × Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'roofers',
  'social-media-setup',
  'Roofers have one of the strongest visual content advantages of any trade. The dramatic transformation of a stripped-back, weathered roof into a pristine new installation is inherently compelling content. Time-lapse videos of roof installations showcase craftsmanship and efficiency. Before-and-after shots of storm damage repairs demonstrate emergency capability. Drone photography of completed projects provides perspectives that ground-level photos cannot match. When a neighbour sees your drone footage of a beautifully finished slate roof three streets away, they start thinking about their own roof. Roofing also generates organic community engagement when storms hit. Posting rapid-response storm damage content during and after severe weather events demonstrates your capability at exactly the moment when homeowners are most concerned about their own roofs. A post showing your team making emergency repairs during a storm, shared in local community groups, generates immediate enquiries from neighbours who noticed their own damage during the same event. The challenge is capturing this content consistently when your team is working at height and focused on the job. We set up social media profiles and content capture systems that make it practical for roofing crews to document their work without disrupting the installation schedule.',
  'Roofing projects are visible to entire neighbourhoods for days or weeks during installation. Every neighbour who walks past scaffolding on their street is a potential customer. Social media extends this neighbourhood visibility beyond the immediate street to the entire local community. When project photos are shared and tagged in local groups, your completed work generates enquiries from homeowners miles away who would never have seen your scaffolding in person.',
  'We create content systems around the visual impact of roofing work. Drone photography captures completed projects from angles that showcase the full scope of work. Time-lapse sequences condense multi-day installations into compelling short videos. Storm response content positions your company as the emergency roofer during severe weather events.',
  '[{"title": "Stunning completed roof work never photographed or shared", "description": "A beautifully installed slate roof or a transformed flat roof represents hours of skilled craftsmanship that looks genuinely impressive when photographed well. Yet most roofing companies never capture this visual evidence of their work. The scaffolding comes down, the crew moves to the next job, and your best marketing content is never created."}, {"title": "No presence during storm events when homeowners are most concerned", "description": "After a storm, local community groups are flooded with posts about damage, flooding, and roof concerns. Roofing companies with active social profiles can respond to these conversations with helpful advice, storm damage information, and evidence of their emergency response capability. Without a social presence, you are invisible during the moments of highest local engagement."}, {"title": "Drone photography capability not used for marketing content", "description": "Many roofing companies own drones for survey purposes but never use the footage for marketing. Aerial photography of completed roofing projects is among the most engaging content any trade can produce, showing the full scale and quality of the work. This capability sits unused while the company struggles to create interesting social content."}]',
  '[{"title": "Project photography system with drone content capture", "description": "A structured photography workflow capturing before, during, and after images of every significant project. Drone footage of completed roofs is captured during final inspection flights. Images are edited and scheduled into social posts showcasing your craftsmanship. Each completed project generates a week of social content."}, {"title": "Storm response social media strategy", "description": "Pre-planned storm response content ready to deploy when severe weather is forecast or underway. Posts include safety advice, temporary repair guidance, and your emergency availability. During and after storms, rapid-response content showing your team addressing damage demonstrates capability when local homeowners are most concerned about their own roofs."}, {"title": "Professional profiles with project portfolio and review integration", "description": "Facebook, Instagram, and Google Business profiles set up with professional imagery, categorised project galleries, and displayed reviews. Instagram reels showcase time-lapse installations and drone footage. Facebook posts target local community engagement. Google Business posts improve search visibility for roofing terms in your area."}]',
  '[{"question": "What social media content works best for roofers?", "answer": "Before-and-after project photos, drone footage of completed roofs, time-lapse installation videos, and storm damage repair posts generate the highest engagement. Educational content about roof maintenance and seasonal care builds trust. The visual nature of roofing work makes it one of the most naturally engaging trades on social media."}, {"question": "Should we use drone footage for social media?", "answer": "Absolutely. If you already fly drones for surveys, capturing marketing footage adds minimal time. Aerial shots of completed roofs show the full scope and quality of your work in a way ground-level photos cannot. Drone content consistently outperforms standard photos for engagement and shares on every social platform."}, {"question": "How do we handle social media during storm events?", "answer": "We prepare storm response content in advance: safety advice posts, temporary repair guidance, and your emergency availability messaging. When severe weather is forecast, these are deployed on your social profiles and in relevant local community groups. Post-storm, rapid updates showing your emergency response demonstrate capability to homeowners assessing their own damage."}, {"question": "Which platforms matter most for roofers?", "answer": "Facebook is essential for local community engagement and storm event visibility. Instagram showcases your visual portfolio and drone footage. Google Business posts improve local search rankings. We set up all three with content systems that cross-post efficiently, maximising reach without tripling your content creation effort."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
